package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AdmissionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions")public class AdmissionListServlet extends HttpServlet{private final AdmissionService service;public AdmissionListServlet(){this(new AdmissionServiceImpl());}public AdmissionListServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int p=Math.max(1,AdmissionRequest.number(q.getParameter("page"),1)),z=Math.min(100,Math.max(1,AdmissionRequest.number(q.getParameter("size"),10)));q.setAttribute("admissionPage",service.listAdmissions(new PageRequest(p,z,q.getParameter("search")),AdmissionRequest.id(q.getParameter("patientId")),AdmissionRequest.id(q.getParameter("doctorId")),AdmissionRequest.id(q.getParameter("departmentId")),AdmissionRequest.id(q.getParameter("roomId")),AdmissionRequest.date(q.getParameter("dateFrom")),AdmissionRequest.date(q.getParameter("dateTo")),q.getParameter("status"),AdmissionRequest.user(q)));q.getRequestDispatcher("/WEB-INF/views/admissions/list.jsp").forward(q,r);}}
